import { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { List, BarChart3, FolderOpen, Calendar, Timer, FileText, TrendingUp, Clock, Activity, Settings as SettingsIcon } from 'lucide-react';
import { TimeEntryList } from '../components/TimeEntryList';
import { TimeEntrySummary } from '../components/TimeEntrySummary';
import { EditTimeEntryModal } from '../components/EditTimeEntryModal';
import { EventCreateModal } from '../components/EventCreateModal';
import { ProjectManager } from '../components/ProjectManager';
import { TimeEntryCalendar } from '../components/TimeEntryCalendar';
import { TimeTrackingTimer } from '../components/TimeTrackingTimer';
import { InvoiceBuilder } from '../components/InvoiceBuilder';
import { AdvancedReports } from '../components/AdvancedReports';
import { PomodoroTimer } from '../components/PomodoroTimer';
import { ActivityTimeline } from '../components/ActivityTimeline';
import { AutoTrackingSettings } from '../components/AutoTrackingSettings';
import { PageHeader } from '../components/PageHeader';
import type { TimeEntry, CalendarEvent } from '../types';

type TabType = 'timer' | 'entries' | 'summary' | 'calendar' | 'projects' | 'invoices' | 'reports' | 'pomodoro' | 'timeline' | 'settings';

const VALID_TABS: TabType[] = ['timer', 'entries', 'summary', 'calendar', 'projects', 'invoices', 'reports', 'pomodoro', 'timeline', 'settings'];

/**
 * TimeTracking Page (Now with Event Planning!)
 * UNIFIED: Time tracking + Event planning in one beautiful interface
 */
export function TimeTracking() {
  const location = useLocation();
  const navigate = useNavigate();

  // Read initial tab from URL query params
  const getTabFromUrl = (): TabType => {
    const params = new URLSearchParams(location.search);
    const tab = params.get('tab');
    if (tab && VALID_TABS.includes(tab as TabType)) {
      return tab as TabType;
    }
    return 'calendar'; // Default tab
  };

  const [activeTab, setActiveTab] = useState<TabType>(getTabFromUrl);

  // Update tab when URL changes
  useEffect(() => {
    const newTab = getTabFromUrl();
    if (newTab !== activeTab) {
      setActiveTab(newTab);
    }
  }, [location.search]);

  // Update URL when tab changes
  const handleTabChange = (tab: TabType) => {
    setActiveTab(tab);
    navigate(`/schedule?tab=${tab}`, { replace: true });
  };
  const [editingEntry, setEditingEntry] = useState<TimeEntry | null>(null);
  const [eventModalData, setEventModalData] = useState<{ dateKey: string; event?: CalendarEvent } | null>(null);

  return (
    <div className="schedule-page">
      {/* Page Header */}
      <PageHeader />

      {/* Tab Navigation */}
      <div className="mb-6 border-b border-border-light dark:border-border-dark">
        <div className="flex gap-1">
          <button
            onClick={() => handleTabChange('timer')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'timer'
                ? 'border-accent-magenta dark:border-accent-cyan text-accent-magenta dark:text-accent-cyan'
                : 'border-transparent text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
            }`}
          >
            <Timer className="w-4 h-4" />
            Timer
          </button>
          <button
            onClick={() => handleTabChange('entries')}
            className={`flex items-center gap-2 px-4 py-3 text-sm font-medium border-b-2 transition-colors ${
              activeTab === 'entries'
