   344→
   345→  const handleDragEnd = (event: DragEndEvent) => {
   346→    const { active, over } = event;
   347→
   348→    if (over && active.id !== over.id) {
   349→      const oldIndex = navOrder.indexOf(active.id as string);
   350→      const newIndex = navOrder.indexOf(over.id as string);
   351→
   352→      if (oldIndex !== -1 && newIndex !== -1) {
